 20→const NICKNAME_KEY = '@basra/nickname';
 21→
 22→export default function HomeScreen() {
 23→  const router = useRouter();
 24→  const { createRoom, joinRoom } = useSocket();
 25→  const { nickname, setNickname, setIsHost, setRoomCode, roomCode, targetScore } = useAppStore();
 26→
 27→  const [joinCode, setJoinCode] = useState('');
 28→  const [showJoin, setShowJoin] = useState(false);
 29→  const [loading, setLoading] = useState(false);
 30→
 31→  useEffect(() => {
 32→    AsyncStorage.getItem(NICKNAME_KEY).then((saved) => {
 33→      if (saved) setNickname(saved);
 34→    });
 35→  }, []);
 36→
 37→  const saveNickname = (name: string) => {
 38→    setNickname(name);
 39→    AsyncStorage.setItem(NICKNAME_KEY, name);
 40→  };
 41→
 42→  const handleCreate = useCallback(() => {
 43→    if (!nickname.trim()) {
 44→      Alert.alert('Enter a nickname', 'Please enter your name first.');
 45→      return;
 46→    }
 47→    setLoading(true);
 48→    setIsHost(true);
 49→
 50→    const socket = getSocket();
 51→
 52→    const onRoomCreated = () => {
 53→      cleanup();
 54→      router.push('/lobby');
 55→    };
 56→    const onError = (data: { message: string }) => {
 57→      cleanup();
 58→      Alert.alert('Error', data.message);
 59→    };
 60→    const cleanup = () => {
 61→      setLoading(false);
 62→      socket.off('room-created', onRoomCreated);
 63→      socket.off('error', onError);
 64→    };
 65→
 66→    socket.on('room-created', onRoomCreated);
 67→    socket.on('error', onError);
 68→
 69→    createRoom(nickname.trim(), targetScore);
 70→  }, [nickname, targetScore, createRoom, setIsHost, router]);
 71→
 72→  const handleJoin = useCallback(() => {
 73→    if (!nickname.trim()) {
 74→      Alert.alert('Enter a nickname', 'Please enter your name first.');
 75→      return;
 76→    }
 77→    if (!joinCode.trim()) {
 78→      Alert.alert('Enter room code', 'Please enter a room code to join.');
 79→      return;
 80→    }
 81→    setLoading(true);
 82→    setIsHost(false);
 83→
 84→    const socket = getSocket();
 85→
 86→    const onRoomJoined = () => {
 87→      cleanup();
 88→      router.push('/lobby');
 89→    };
 90→    const onError = (data: { message: string }) => {
 91→      cleanup();
 92→      Alert.alert('Error', data.message);
 93→    };
 94→    const cleanup = () => {
 95→      setLoading(false);
 96→      socket.off('room-joined', onRoomJoined);
 97→      socket.off('error', onError);
 98→    };
 99→
100→    socket.on('room-joined', onRoomJoined);
101→    socket.on('error', onError);
102→
103→    joinRoom(joinCode.trim().toUpperCase(), nickname.trim());
104→  }, [nickname, joinCode, joinRoom, setIsHost, router]);
105→
106→  return (
107→    <KeyboardAvoidingView
108→      style={styles.container}
109→      behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
110→    >
111→      <View style={styles.content}>
112→        <Text style={styles.title}>BASRA</Text>
113→        <Text style={styles.subtitle}>Egyptian Card Game</Text>
114→
115→        <View style={styles.inputContainer}>
116→          <Text style={styles.label}>Your Nickname</Text>
117→          <TextInput
118→            style={styles.input}
119→            value={nickname}
120→            onChangeText={saveNickname}
121→            placeholder="Enter your name"
122→            placeholderTextColor={colors.textMuted}
123→            maxLength={20}
124→            autoCapitalize="words"
125→          />
126→        </View>
127→
128→        <TouchableOpacity style={styles.primaryButton} onPress={handleCreate} disabled={loading}>
129→          {loading && !showJoin ? (
130→            <ActivityIndicator color={colors.text} />
131→          ) : (
132→            <Text style={styles.primaryButtonText}>Create Game</Text>
133→          )}
134→        </TouchableOpacity>
135→
136→        {!showJoin ? (
137→          <TouchableOpacity
138→            style={styles.secondaryButton}
139→            onPress={() => setShowJoin(true)}
140→            disabled={loading}
141→          >
142→            <Text style={styles.secondaryButtonText}>Join Game</Text>
143→          </TouchableOpacity>
144→        ) : (
145→          <View style={styles.joinContainer}>
146→            <TextInput
147→              style={styles.codeInput}
148→              value={joinCode}
149→              onChangeText={setJoinCode}
150→              placeholder="ROOM CODE"
151→              placeholderTextColor={colors.textMuted}
152→              maxLength={5}
153→              autoCapitalize="characters"
154→              autoCorrect={false}
155→              editable={!loading}
156→            />
157→            <TouchableOpacity style={styles.joinButton} onPress={handleJoin} disabled={loading}>
158→              {loading ? (
159→                <ActivityIndicator color={colors.text} />
160→              ) : (
161→                <Text style={styles.primaryButtonText}>Join</Text>
162→              )}
163→            </TouchableOpacity>
164→          </View>
165→        )}
166→
167→        <Text style={styles.targetText}>
168→          Target Score: {targetScore} pts
169→        </Text>
170→      </View>
171→    </KeyboardAvoidingView>
172→  );
173→}
