 1→import { useCallback } from 'react';
 2→import {
 3→  useSharedValue,
 4→  withTiming,
 5→  withSpring,
 6→  withSequence,
 7→  Easing,
 8→} from 'react-native-reanimated';
 9→
10→export function useCardAnimation() {
11→  const scale = useSharedValue(1);
12→  const translateY = useSharedValue(0);
13→  const rotate = useSharedValue(0);
14→  const opacity = useSharedValue(1);
15→
16→  const playToTable = useCallback(() => {
17→    translateY.value = withSpring(-200, { damping: 12, stiffness: 100 });
18→    scale.value = withSequence(
19→      withTiming(1.1, { duration: 100 }),
20→      withTiming(1, { duration: 200 })
21→    );
22→  }, []);
23→
24→  const captureAnimation = useCallback(() => {
25→    scale.value = withSequence(
26→      withTiming(1.2, { duration: 150 }),
27→      withTiming(0, { duration: 300, easing: Easing.in(Easing.ease) })
28→    );
29→    opacity.value = withTiming(0, { duration: 450 });
30→  }, []);
31→
32→  const dealAnimation = useCallback((delay: number = 0) => {
33→    scale.value = 0;
34→    opacity.value = 0;
35→    translateY.value = -100;
36→
37→    setTimeout(() => {
38→      scale.value = withSpring(1, { damping: 10, stiffness: 80 });
39→      opacity.value = withTiming(1, { duration: 300 });
40→      translateY.value = withSpring(0, { damping: 12, stiffness: 80 });
41→    }, delay);
42→  }, []);
43→
44→  const basraCelebration = useCallback(() => {
45→    scale.value = withSequence(
46→      withTiming(1.5, { duration: 200 }),
47→      withSpring(1, { damping: 5, stiffness: 100 })
48→    );
49→    rotate.value = withSequence(
50→      withTiming(-0.1, { duration: 100 }),
51→      withTiming(0.1, { duration: 100 }),
52→      withTiming(0, { duration: 100 })
53→    );
54→  }, []);
55→
56→  return {
57→    scale,
58→    translateY,
59→    rotate,
60→    opacity,
61→    playToTable,
62→    captureAnimation,
63→    dealAnimation,
64→    basraCelebration,
65→  };
66→}
