 1→import { Card, CaptureResult } from './types';
 2→import { DIAMOND_7_ID } from './constants';
 3→import { detectBasra } from './basra';
 4→
 5→function isJack(card: Card): boolean {
 6→  return card.rank === 'J';
 7→}
 8→
 9→function isDiamond7(card: Card): boolean {
10→  return card.id === DIAMOND_7_ID;
11→}
12→
13→/**
14→ * Find all subsets of `cards` whose values sum to `target`.
15→ * Returns an array of card arrays (each inner array is one valid subset).
16→ */
17→function findSubsetsWithSum(cards: Card[], target: number): Card[][] {
18→  const results: Card[][] = [];
19→
20→  function backtrack(start: number, current: Card[], currentSum: number) {
21→    if (currentSum === target && current.length > 0) {
22→      results.push([...current]);
23→    }
24→    if (currentSum >= target) return;
25→
26→    for (let i = start; i < cards.length; i++) {
27→      current.push(cards[i]);
28→      backtrack(i + 1, current, currentSum + cards[i].value);
29→      current.pop();
30→    }
31→  }
32→
33→  backtrack(0, [], 0);
34→  return results;
35→}
36→
37→/**
38→ * Given a played card and the current table cards, determine what gets captured.
39→ *
40→ * Rules:
41→ * - Jack or Diamond 7: sweep all table cards
42→ * - Queen: captures only other Queens
43→ * - King: captures only other Kings
44→ * - Numeral (A, 2-10): captures cards of same rank + any combination of numerals summing to its value
45→ */
46→export function findCaptures(played: Card, table: Card[]): Card[] {
47→  if (table.length === 0) return [];
48→
49→  // Jack sweeps all
50→  if (isJack(played)) {
51→    return [...table];
52→  }
53→
54→  // Diamond 7 sweeps all
55→  if (isDiamond7(played)) {
56→    return [...table];
57→  }
58→
59→  // Queen captures only queens
60→  if (played.rank === 'Q') {
61→    const queens = table.filter(c => c.rank === 'Q');
62→    return queens.length > 0 ? queens : [];
63→  }
64→
65→  // King captures only kings
66→  if (played.rank === 'K') {
67→    const kings = table.filter(c => c.rank === 'K');
68→    return kings.length > 0 ? kings : [];
69→  }
70→
71→  // Numeral card: capture same rank + sum combinations
72→  const sameRank = table.filter(c => c.rank === played.rank);
73→  const remaining = table.filter(
74→    c => !sameRank.includes(c) && c.value > 0 // exclude face cards and same-rank cards
75→  );
76→
77→  const sumSubsets = findSubsetsWithSum(remaining, played.value);
78→
79→  // Combine: same rank cards + all cards from sum subsets (deduplicated)
80→  const captured = new Set<Card>(sameRank);
81→  for (const subset of sumSubsets) {
82→    for (const card of subset) {
83→      captured.add(card);
84→    }
85→  }
86→
87→  return captured.size > 0 ? Array.from(captured) : [];
88→}
89→
90→/**
91→ * Process a card play: find captures and detect basra.
92→ */
93→export function processPlay(played: Card, table: Card[]): CaptureResult {
94→  const captured = findCaptures(played, table);
95→  const basraType = detectBasra(played, table, captured);
96→
97→  return { captured, basraType };
98→}
