 1→import { useEffect } from 'react';
 2→import { StyleSheet } from 'react-native';
 3→import Animated, {
 4→  useSharedValue,
 5→  useAnimatedStyle,
 6→  withSequence,
 7→  withTiming,
 8→  withSpring,
 9→  withDelay,
10→  runOnJS,
11→} from 'react-native-reanimated';
