14→
15→interface BasraToastProps {
16→  visible: boolean;
17→  isJackBasra: boolean;
18→  onHide: () => void;
19→}
20→
21→export default function BasraToast({ visible, isJackBasra, onHide }: BasraToastProps) {
22→  const scale = useSharedValue(0);
23→  const opacity = useSharedValue(0);
24→
25→  useEffect(() => {
26→    if (visible) {
27→      basraVibration();
28→      scale.value = withSequence(
29→        withSpring(1.3, { damping: 5, stiffness: 200 }),
30→        withSpring(1, { damping: 8 })
31→      );
32→      opacity.value = withSequence(
33→        withTiming(1, { duration: 200 }),
34→        withDelay(1500, withTiming(0, { duration: 400 }, () => {
35→          runOnJS(onHide)();
36→        }))
37→      );
38→    } else {
39→      scale.value = 0;
40→      opacity.value = 0;
41→    }
42→  }, [visible]);
43→
44→  const animatedStyle = useAnimatedStyle(() => ({
45→    transform: [{ scale: scale.value }],
46→    opacity: opacity.value,
47→  }));
48→
49→  if (!visible) return null;
50→
51→  return (
52→    <Animated.View style={[styles.container, animatedStyle]}>
53→      <Animated.Text style={[styles.text, isJackBasra && styles.jackText]}>
54→        {isJackBasra ? 'JACK BASRA!' : 'BASRA!'}
55→      </Animated.Text>
56→      <Animated.Text style={styles.points}>
57→        +{isJackBasra ? 30 : 10} pts
58→      </Animated.Text>
59→    </Animated.View>
60→  );
61→}
