 1→import { Card } from './types';
 2→import { SUITS, RANKS, RANK_VALUES } from './constants';
 3→
 4→export function createDeck(): Card[] {
 5→  const deck: Card[] = [];
 6→  for (const suit of SUITS) {
 7→    for (const rank of RANKS) {
 8→      deck.push({
 9→        id: `${rank}-${suit}`,
10→        suit,
11→        rank,
12→        value: RANK_VALUES[rank],
13→      });
14→    }
15→  }
16→  return deck;
17→}
18→
19→/** Fisher-Yates shuffle */
20→export function shuffleDeck(deck: Card[]): Card[] {
21→  const shuffled = [...deck];
22→  for (let i = shuffled.length - 1; i > 0; i--) {
23→    const j = Math.floor(Math.random() * (i + 1));
24→    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
25→  }
26→  return shuffled;
27→}
28→
29→export function dealCards(deck: Card[], count: number): { dealt: Card[]; remaining: Card[] } {
30→  const dealt = deck.slice(0, count);
31→  const remaining = deck.slice(count);
32→  return { dealt, remaining };
33→}
