        : state.opponentCardCount - 1,
      // Update captured counts
      players: state.players.map((p) =>
        p.id === data.playerId
          ? { ...p, capturedCount: data.playerCapturedCount }
          : p
      ),
    });
  },

  onRoundEnd: (data) =>
    set({
      phase: 'round-end',
      roundEndData: data,
      players: data.players.map((p) => ({
        id: p.id,
        nickname: p.nickname,
        score: p.totalScore,
        capturedCount: p.capturedCount,
        basras: p.basras,
        jackBasras: p.jackBasras,
      })),
    }),

  onGameOver: (data) =>
    set({
      phase: 'game-over',
      gameOverData: data,
    }),

  setOpponentConnected: (connected) => set({ opponentConnected: connected }),

  isMyTurn: () => {
    const state = get();
    return state.currentTurn === state.myId;
  },

  reset: () =>
    set({
      phase: 'waiting',
      hand: [],
      table: [],
      deckRemaining: 0,
      currentTurn: null,
      dealer: null,
      myId: null,
      opponentCardCount: 0,
      roundNumber: 0,
      players: [],
      lastPlay: null,
      roundEndData: null,
      gameOverData: null,
      opponentConnected: true,
    }),
}));

