            runOnJS(clearPreview)();
          }
        })
        .onFinalize(() => {
          'worklet';
          entity.isDragging.value = 0;
        });
    },
    [layout, isMyTurn, showCapturePreview, clearPreview, onPlayCard]
  );

  return { createDragGesture };
