  1→import { useCallback, useRef } from 'react';
  2→import { Gesture } from 'react-native-gesture-handler';
  3→import { runOnJS, withSpring } from 'react-native-reanimated';
  4→import type { Card } from '@basra/shared';
  5→import { findCaptures } from '@basra/shared';
  6→import type { CardEntity, GameLayout } from './types';
  7→import type { CardEntitiesManager } from './useCardEntities';
  8→import {
  9→  DRAG_SCALE,
 10→  PREVIEW_WOBBLE_SCALE,
 11→  SPRING_SETTLE,
 12→} from './springs';
 13→import { animateSpring } from './utils';
 14→
 15→interface DragToPlayOptions {
 16→  entities: CardEntitiesManager;
 17→  layout: GameLayout | null;
 18→  isMyTurn: boolean;
 19→  table: Card[];
 20→  onPlayCard: (cardId: string) => void;
 21→}
 22→
 23→export function useDragToPlay({
 24→  entities,
 25→  layout,
 26→  isMyTurn,
 27→  table,
 28→  onPlayCard,
 29→}: DragToPlayOptions) {
 30→  const previewingRef = useRef<string[]>([]);
 31→  const startPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
 32→
 33→  const clearPreview = useCallback(() => {
 34→    for (const id of previewingRef.current) {
 35→      const e = entities.getEntity(id);
 36→      if (e) {
 37→        e.scale.value = withSpring(1, SPRING_SETTLE);
 38→      }
 39→    }
 40→    previewingRef.current = [];
 41→  }, [entities]);
 42→
 43→  const showCapturePreview = useCallback(
 44→    (card: Card) => {
 45→      clearPreview();
 46→      const captures = findCaptures(card, table);
 47→      for (const captured of captures) {
 48→        const e = entities.getEntity(captured.id);
 49→        if (e) {
 50→          animateSpring(e.scale, PREVIEW_WOBBLE_SCALE, {
 51→            damping: 4,
 52→            stiffness: 200,
 53→            mass: 0.5,
 54→          });
 55→          previewingRef.current.push(captured.id);
 56→        }
 57→      }
 58→    },
 59→    [entities, table, clearPreview]
 60→  );
 61→
 62→  const createDragGesture = useCallback(
 63→    (entity: CardEntity) => {
 64→      if (!layout) return Gesture.Pan();
 65→
