 38→
 39→/**
 40→ * Game Start: shuffle jiggle → deal to opponent → deal to table → deal to hand
 41→ */
 42→export async function gameStartSequence(
 43→  entities: CardEntitiesManager,
 44→  layout: GameLayout,
 45→  payload: GameStartPayload
 46→): Promise<void> {
 47→  // Shuffle jiggle on deck
 48→  const deckEntities = entities.getEntitiesByZone('deck');
 49→  for (let cycle = 0; cycle < SHUFFLE_CYCLES; cycle++) {
 50→    for (const e of deckEntities) {
 51→      e.rotation.value = cycle % 2 === 0 ? 0.05 : -0.05;
 52→      e.x.value += cycle % 2 === 0 ? 4 : -4;
 53→    }
 54→    await delay(SHUFFLE_CYCLE_MS);
 55→  }
 56→  // Reset deck
 57→  for (const e of deckEntities) {
 58→    e.rotation.value = 0;
 59→  }
 60→
 61→  // Deal cards to opponent (staggered, face-down)
 62→  const oppCenter = {
 63→    x: layout.opponentHand.x + layout.opponentHand.width / 2,
 64→    y: layout.opponentHand.y + layout.opponentHand.height / 2 + 15,
 65→  };
 66→  const oppEntities = entities.getEntitiesByZone('opponentHand');
 67→  const oppPositions = getOpponentHandPositions(oppEntities.length, oppCenter);
 68→
 69→  for (let i = 0; i < oppEntities.length; i++) {
 70→    const e = oppEntities[i];
 71→    const pos = oppPositions[i];
 72→    if (pos) {
 73→      // Start from deck position
 74→      e.x.value = layout.deck.x + layout.deck.width / 2;
 75→      e.y.value = layout.deck.y + layout.deck.height / 2;
 76→      e.opacity.value = 1;
 77→      e.scale.value = 0.3;
 78→
 79→      // Fly to position
 80→      animateSpring(e.scale, 1, SPRING_CARD);
 81→      animatePosition(e, pos.x, pos.y, SPRING_CARD);
 82→      fireSpring(e.rotation, pos.rotation, SPRING_CARD);
 83→      await delay(DEAL_STAGGER);
 84→    }
 85→  }
 86→
 87→  // Deal cards to table (staggered, flip to face-up mid-flight)
 88→  const tableEntities = entities.getEntitiesByZone('table');
 89→  const tablePositions = getTablePositions(tableEntities.length, layout.table);
 90→
 91→  for (let i = 0; i < tableEntities.length; i++) {
 92→    const e = tableEntities[i];
 93→    const pos = tablePositions[i];
 94→    if (pos) {
 95→      e.x.value = layout.deck.x + layout.deck.width / 2;
 96→      e.y.value = layout.deck.y + layout.deck.height / 2;
 97→      e.opacity.value = 1;
 98→      e.scale.value = 0.3;
 99→      e.faceUp = false;
100→
101→      // Fly to position
102→      animateSpring(e.scale, 1, SPRING_CARD);
103→      animatePosition(e, pos.x, pos.y, SPRING_CARD);
104→      fireSpring(e.rotation, pos.rotation, SPRING_CARD);
105→
106→      // Flip mid-flight
107→      delay(80).then(() => {
108→        animateTiming(e.scaleX, 0, TIMING_FLIP).then(() => {
109→          e.faceUp = true;
110→          animateTiming(e.scaleX, 1, TIMING_FLIP);
111→        });
112→      });
113→
114→      await delay(DEAL_STAGGER);
115→    }
116→  }
117→
118→  // Deal cards to hand (staggered, face-up, fan arc)
119→  const handCenter = {
120→    x: layout.myHand.x + layout.myHand.width / 2,
121→    y: layout.myHand.y + layout.myHand.height / 2,
122→  };
123→  const handEntities = entities.getEntitiesByZone('hand');
124→  const handPositions = getHandPositions(handEntities.length, handCenter);
125→
126→  for (let i = 0; i < handEntities.length; i++) {
127→    const e = handEntities[i];
128→    const pos = handPositions[i];
129→    if (pos) {
130→      e.x.value = layout.deck.x + layout.deck.width / 2;
131→      e.y.value = layout.deck.y + layout.deck.height / 2;
132→      e.opacity.value = 1;
133→      e.scale.value = 0.3;
134→
135→      animateSpring(e.scale, 1, SPRING_CARD);
136→      animatePosition(e, pos.x, pos.y, SPRING_CARD);
137→      fireSpring(e.rotation, pos.rotation, SPRING_CARD);
138→      lightTap();
139→      await delay(DEAL_STAGGER);
140→    }
141→  }
142→
143→  // Wait for last animation to settle
144→  await delay(300);
145→}
