147→/**
148→ * Mid-round deal: new cards fly from deck to hand + opponent
149→ */
150→export async function dealSequence(
151→  entities: CardEntitiesManager,
152→  layout: GameLayout,
153→  payload: CardsDealtPayload
154→): Promise<void> {
155→  // Will be handled by sync + position (game state update triggers entity sync)
156→  // Animate new hand cards from deck
157→  const handCenter = {
158→    x: layout.myHand.x + layout.myHand.width / 2,
159→    y: layout.myHand.y + layout.myHand.height / 2,
160→  };
