171→      e.scale.value = 0.3;
172→      e.opacity.value = 1;
173→
174→      animateSpring(e.scale, 1, SPRING_CARD);
175→      animatePosition(e, pos.x, pos.y, SPRING_CARD);
176→      fireSpring(e.rotation, pos.rotation, SPRING_CARD);
177→      lightTap();
