179→    }
180→  }
181→
182→  // Opponent gets cards too
183→  const oppCenter = {
184→    x: layout.opponentHand.x + layout.opponentHand.width / 2,
185→    y: layout.opponentHand.y + layout.opponentHand.height / 2 + 15,
186→  };
187→  const oppEntities = entities.getEntitiesByZone('opponentHand');
188→  const oppPositions = getOpponentHandPositions(oppEntities.length, oppCenter);
189→
190→  for (let i = 0; i < oppEntities.length; i++) {
