195→      e.y.value = layout.deck.y + layout.deck.height / 2;
196→      e.scale.value = 0.3;
197→      e.opacity.value = 1;
198→
199→      animateSpring(e.scale, 1, SPRING_CARD);
200→      animatePosition(e, pos.x, pos.y, SPRING_CARD);
201→      fireSpring(e.rotation, pos.rotation, SPRING_CARD);
202→      await delay(DEAL_STAGGER);
203→    }
204→  }
205→
206→  await delay(200);
