209→/**
210→ * My card played: card snaps to table → capture animation → re-fan hand
211→ */
212→export async function myPlaySequence(
213→  entities: CardEntitiesManager,
214→  layout: GameLayout,
215→  payload: CardPlayedPayload
216→): Promise<void> {
217→  const cardEntity = entities.getEntity(payload.card.id);
218→
219→  if (cardEntity) {
220→    // Snap to table center
221→    const tableCenter = {
222→      x: layout.table.x + layout.table.width / 2,
223→      y: layout.table.y + layout.table.height / 2,
224→    };
225→    await animatePosition(cardEntity, tableCenter.x, tableCenter.y, SPRING_QUICK);
226→    cardEntity.zone = 'table';
227→    cardEntity.zIndex.value = 50;
228→  }
229→
230→  // Capture animation
231→  if (payload.capturedCards.length > 0) {
232→    await delay(CAPTURE_PAUSE);
233→
234→    // Haptic
235→    if (payload.isBasra || payload.isJackBasra) {
236→      basraVibration();
237→    } else {
238→      mediumTap();
239→    }
240→
241→    // Converge all captured + played card to center
242→    const centerX = layout.table.x + layout.table.width / 2;
243→    const centerY = layout.table.y + layout.table.height / 2;
244→
245→    const captureTargets = [
246→      ...payload.capturedCards.map((c) => entities.getEntity(c.id)),
247→      cardEntity,
248→    ].filter(Boolean) as import('./types').CardEntity[];
249→
250→    // Converge
251→    await Promise.all(
252→      captureTargets.map((e) =>
253→        animatePosition(e, centerX, centerY, SPRING_QUICK)
254→      )
255→    );
256→
257→    // Scale pulse
258→    await Promise.all(
259→      captureTargets.map((e) => animateSpring(e.scale, 1.15, SPRING_BOUNCY))
260→    );
261→
262→    // Fly to my pile (staggered)
263→    for (let i = 0; i < captureTargets.length; i++) {
264→      const e = captureTargets[i];
265→      e.zone = 'myPile';
266→      animateSpring(e.scale, 0.5, SPRING_HEAVY);
267→      animateSpring(e.opacity, 0, SPRING_HEAVY);
268→      animatePosition(
269→        e,
270→        layout.myPile.x + layout.myPile.width / 2,
271→        layout.myPile.y + layout.myPile.height / 2,
272→        SPRING_HEAVY
273→      );
274→      await delay(CAPTURE_FLY_STAGGER);
275→    }
276→
277→    await delay(200);
278→
279→    // Remove captured entities
280→    for (const e of captureTargets) {
281→      entities.removeEntity(e.id);
282→    }
283→  } else {
284→    // No capture: card joins table, reposition all table cards
285→    if (cardEntity) {
286→      cardEntity.zone = 'table';
287→    }
288→  }
289→
290→  // Re-fan remaining hand cards
291→  const handEntities = entities.getEntitiesByZone('hand');
292→  const handCenter = {
293→    x: layout.myHand.x + layout.myHand.width / 2,
294→    y: layout.myHand.y + layout.myHand.height / 2,
295→  };
296→  const handPositions = getHandPositions(handEntities.length, handCenter);
297→
298→  handEntities.forEach((e, i) => {
299→    if (handPositions[i]) {
300→      animatePosition(e, handPositions[i].x, handPositions[i].y, SPRING_CARD);
301→      fireSpring(e.rotation, handPositions[i].rotation, SPRING_CARD);
302→      e.zIndex.value = 10 + i;
303→    }
304→  });
305→
306→  // Re-position table cards
307→  const tableEntities = entities.getEntitiesByZone('table');
308→  const tablePositions = getTablePositions(tableEntities.length, layout.table);
309→  tableEntities.forEach((e, i) => {
310→    if (tablePositions[i]) {
311→      animatePosition(e, tablePositions[i].x, tablePositions[i].y, SPRING_CARD);
312→      fireSpring(e.rotation, tablePositions[i].rotation, SPRING_CARD);
313→    }
314→  });
315→}
