317→/**
318→ * Opponent plays: card flies from opponent area → flip → capture/place
319→ */
320→export async function opponentPlaySequence(
321→  entities: CardEntitiesManager,
322→  layout: GameLayout,
323→  payload: CardPlayedPayload
324→): Promise<void> {
325→  // Create entity for the opponent's played card
326→  const oppCenter = {
327→    x: layout.opponentHand.x + layout.opponentHand.width / 2,
328→    y: layout.opponentHand.y + layout.opponentHand.height / 2 + 15,
329→  };
330→
331→  // Remove one opponent hand entity (the one that "played")
332→  const oppEntities = entities.getEntitiesByZone('opponentHand');
333→  let flyingEntity: import('./types').CardEntity | null = null;
334→
335→  if (oppEntities.length > 0) {
336→    flyingEntity = oppEntities[oppEntities.length - 1];
337→    // Give it the real card data
338→    flyingEntity.card = payload.card;
339→    flyingEntity.zone = 'table';
340→  } else {
341→    // Fallback: create a new entity
342→    flyingEntity = entities.addEntity(
343→      payload.card.id,
344→      payload.card,
345→      false,
346→      'table',
347→      oppCenter.x,
348→      oppCenter.y
349→    );
350→  }
351→
352→  // Fly to table center
353→  const tableCenter = {
354→    x: layout.table.x + layout.table.width / 2,
355→    y: layout.table.y + layout.table.height / 2,
356→  };
357→
358→  flyingEntity.zIndex.value = 50;
359→  await animatePosition(flyingEntity, tableCenter.x, tableCenter.y, SPRING_CARD);
360→
361→  // Flip effect: scaleX 1→0, swap content, scaleX 0→1
362→  await animateTiming(flyingEntity.scaleX, 0, TIMING_FLIP);
363→  flyingEntity.faceUp = true;
364→  flyingEntity.id = payload.card.id; // Update ID to match the real card
365→  await animateTiming(flyingEntity.scaleX, 1, TIMING_FLIP);
366→
367→  // Capture animation
368→  if (payload.capturedCards.length > 0) {
369→    await delay(CAPTURE_PAUSE);
370→
371→    if (payload.isBasra || payload.isJackBasra) {
372→      basraVibration();
373→    } else {
374→      mediumTap();
375→    }
376→
377→    const centerX = layout.table.x + layout.table.width / 2;
378→    const centerY = layout.table.y + layout.table.height / 2;
379→
380→    const captureTargets = [
381→      ...payload.capturedCards.map((c) => entities.getEntity(c.id)),
382→      flyingEntity,
383→    ].filter(Boolean) as import('./types').CardEntity[];
384→
385→    // Converge
386→    await Promise.all(
387→      captureTargets.map((e) =>
388→        animatePosition(e, centerX, centerY, SPRING_QUICK)
389→      )
390→    );
391→
392→    // Pulse
393→    await Promise.all(
394→      captureTargets.map((e) => animateSpring(e.scale, 1.15, SPRING_BOUNCY))
395→    );
396→
397→    // Fly to opponent pile
398→    for (let i = 0; i < captureTargets.length; i++) {
399→      const e = captureTargets[i];
400→      e.zone = 'opponentPile';
401→      animateSpring(e.scale, 0.5, SPRING_HEAVY);
402→      animateSpring(e.opacity, 0, SPRING_HEAVY);
403→      animatePosition(
404→        e,
405→        layout.opponentPile.x + layout.opponentPile.width / 2,
406→        layout.opponentPile.y + layout.opponentPile.height / 2,
407→        SPRING_HEAVY
408→      );
409→      await delay(CAPTURE_FLY_STAGGER);
410→    }
411→
412→    await delay(200);
413→
414→    // Remove captured entities
415→    for (const e of captureTargets) {
416→      entities.removeEntity(e.id);
417→    }
418→  }
419→
420→  // Re-fan opponent hand
421→  const remainingOpp = entities.getEntitiesByZone('opponentHand');
422→  const newOppPositions = getOpponentHandPositions(remainingOpp.length, oppCenter);
423→  remainingOpp.forEach((e, i) => {
424→    if (newOppPositions[i]) {
425→      animatePosition(e, newOppPositions[i].x, newOppPositions[i].y, SPRING_CARD);
426→      fireSpring(e.rotation, newOppPositions[i].rotation, SPRING_CARD);
427→    }
428→  });
429→
430→  // Re-position table cards
