import { useState, useEffect } from 'react';
import { View, StyleSheet, SafeAreaView, Text } from 'react-native';
import { useRouter } from 'expo-router';
import { useSocket } from '../src/hooks/useSocket';
import { useGameStore } from '../src/store/useGameStore';
import { useAppStore } from '../src/store/useAppStore';
import ScoreBar from '../src/components/ScoreBar';
import TurnIndicator from '../src/components/TurnIndicator';
import GameBoard from '../src/components/GameBoard';
import BasraToast from '../src/components/BasraToast';
import { colors, spacing, fontSize } from '../src/theme';

export default function GameScreen() {
  const router = useRouter();
  const { playCard: emitPlayCard } = useSocket();
  const {
    hand,
    table,
    deckRemaining,
    currentTurn,
    myId,
    opponentCardCount,
    roundNumber,
    targetScore,
    players,
    lastPlay,
    phase,
    opponentConnected,
  } = useGameStore();

  const [showBasra, setShowBasra] = useState(false);
  const [isJackBasra, setIsJackBasra] = useState(false);

  const isMyTurn = currentTurn === myId;
  const me = players.find((p) => p.id === myId);
  const opponent = players.find((p) => p.id !== myId);

  // Navigate to score screen on round end or game over
  useEffect(() => {
    if (phase === 'round-end' || phase === 'game-over') {
      router.push('/score');
    }
  }, [phase]);

  // Show basra toast when a basra occurs
  useEffect(() => {
    if (lastPlay && (lastPlay.isBasra || lastPlay.isJackBasra)) {
      setIsJackBasra(lastPlay.isJackBasra);
      setShowBasra(true);
    }
  }, [lastPlay]);

  if (!me || !opponent) {
    return (
      <View style={styles.container}>
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      {/* Score Bar */}
      <ScoreBar
        myScore={me.score}
        opponentScore={opponent.score}
        myName={me.nickname}
        opponentName={opponent.nickname}
        targetScore={targetScore}
        roundNumber={roundNumber}
        deckRemaining={deckRemaining}
      />

      {/* Disconnection Warning */}
      {!opponentConnected && (
        <View style={styles.disconnectBanner}>
          <Text style={styles.disconnectText}>Opponent disconnected...</Text>
        </View>
      )}

      {/* Turn Indicator */}
      <TurnIndicator isMyTurn={isMyTurn} />

      {/* Game Board — single flat card layer with all animations */}
      <GameBoard
        hand={hand}
        table={table}
        opponentCardCount={opponentCardCount}
        deckRemaining={deckRemaining}
        isMyTurn={isMyTurn}
        myId={myId}
        myCapturedCount={me.capturedCount}
        myBasras={me.basras}
        myJackBasras={me.jackBasras}
        opponentCapturedCount={opponent.capturedCount}
        opponentBasras={opponent.basras}
        opponentJackBasras={opponent.jackBasras}
        onPlayCard={emitPlayCard}
      />

      {/* Basra Toast */}
      <BasraToast
        visible={showBasra}
        isJackBasra={isJackBasra}
        onHide={() => setShowBasra(false)}
      />
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.bg,
  },
  loadingText: {
    color: colors.text,
    fontSize: fontSize.lg,
    textAlign: 'center',
    marginTop: 100,
  },
  disconnectBanner: {
    backgroundColor: colors.error,
    paddingVertical: spacing.xs,
    alignItems: 'center',
  },
  disconnectText: {
    color: colors.text,
    fontSize: fontSize.sm,
    fontWeight: '600',
  },
});

import { create } from 'zustand';
import {
  Card,
  GamePhase,
  CardPlayedPayload,
  GameStartPayload,
  CardsDealtPayload,
  RoundEndPayload,
  GameOverPayload,
} from '@basra/shared';

interface PlayerInfo {
  id: string;
  nickname: string;
  score: number;
  capturedCount: number;
  basras: number;
  jackBasras: number;
}

interface GameStore {
  phase: GamePhase;
  hand: Card[];
  table: Card[];
  deckRemaining: number;
  currentTurn: string | null;
  dealer: string | null;
  myId: string | null;
  opponentCardCount: number;
  roundNumber: number;
  targetScore: number;
  players: PlayerInfo[];

  // Last play animation data
  lastPlay: CardPlayedPayload | null;

  // Track last capturer for round-end table card distribution
  lastCapturePlayerId: string | null;

  // Round end data
  roundEndData: RoundEndPayload | null;

  // Game over data
  gameOverData: GameOverPayload | null;

  // Whether opponent is connected
  opponentConnected: boolean;

  // Actions
  setMyId: (id: string) => void;
  onGameStart: (data: GameStartPayload, myId: string) => void;
  onCardsDealt: (data: CardsDealtPayload) => void;
  onCardPlayed: (data: CardPlayedPayload) => void;
  onRoundEnd: (data: RoundEndPayload) => void;
  onGameOver: (data: GameOverPayload) => void;
  setOpponentConnected: (connected: boolean) => void;
  isMyTurn: () => boolean;
  reset: () => void;
}

export const useGameStore = create<GameStore>((set, get) => ({
  phase: 'waiting',
  hand: [],
  table: [],
  deckRemaining: 0,
  currentTurn: null,
  dealer: null,
  myId: null,
  opponentCardCount: 0,
  roundNumber: 0,
  targetScore: 121,
  players: [],
  lastPlay: null,
  lastCapturePlayerId: null,
  roundEndData: null,
  gameOverData: null,
  opponentConnected: true,

  setMyId: (id) => set({ myId: id }),

  onGameStart: (data, myId) =>
    set({
      phase: 'playing',
      hand: data.hand,
      table: data.tableCards,
      deckRemaining: data.deckRemaining,
      currentTurn: data.currentTurn,
      dealer: data.dealer,
      myId,
      opponentCardCount: data.opponentCardCount,
      roundNumber: data.roundNumber,
      targetScore: data.targetScore,
      players: data.players.map((p) => ({
        id: p.id,
        nickname: p.nickname,
        score: p.score,
        capturedCount: 0,
        basras: 0,
        jackBasras: 0,
      })),
      lastPlay: null,
      lastCapturePlayerId: null,
      roundEndData: null,
      gameOverData: null,
    }),

  onCardsDealt: (data) =>
    set({
      hand: data.hand,
      deckRemaining: data.deckRemaining,
      opponentCardCount: data.opponentCardCount,
    }),

  onCardPlayed: (data) => {
    const state = get();
    const isMe = data.playerId === state.myId;

    set({
      table: data.tableAfter,
      currentTurn: data.currentTurn,
      lastPlay: data,
      lastCapturePlayerId:
        data.capturedCards.length > 0 ? data.playerId : state.lastCapturePlayerId,
      // If I played, remove the card from my hand
      hand: isMe
        ? state.hand.filter((c) => c.id !== data.card.id)
        : state.hand,
      // If opponent played, decrement their count
      opponentCardCount: isMe
        ? state.opponentCardCount
        : state.opponentCardCount - 1,
      // Update captured counts
      players: state.players.map((p) =>
        p.id === data.playerId
          ? { ...p, capturedCount: data.playerCapturedCount }
          : p
      ),
    });
  },

  onRoundEnd: (data) =>
    set({
      phase: 'round-end',
      roundEndData: data,
      players: data.players.map((p) => ({
        id: p.id,
        nickname: p.nickname,
        score: p.totalScore,
        capturedCount: p.capturedCount,
        basras: p.basras,
        jackBasras: p.jackBasras,
      })),
    }),

  onGameOver: (data) =>
    set({
      phase: 'game-over',
      gameOverData: data,
    }),

  setOpponentConnected: (connected) => set({ opponentConnected: connected }),

  isMyTurn: () => {
    const state = get();
    return state.currentTurn === state.myId;
  },

  reset: () =>
    set({
      phase: 'waiting',
      hand: [],
      table: [],
      deckRemaining: 0,
      currentTurn: null,
      dealer: null,
      myId: null,
      opponentCardCount: 0,
      roundNumber: 0,
      players: [],
      lastPlay: null,
      lastCapturePlayerId: null,
      roundEndData: null,
      gameOverData: null,
      opponentConnected: true,
    }),
}));

