}: CapturedPileProps) {
  return (
    <View style={[styles.container, { left: x, top: y }]}>
      {/* Stack visual — show up to 3 offset cards */}
      {count > 0 && (
        <View style={styles.stack}>
          {[...Array(Math.min(3, count))].map((_, i) => (
            <View
              key={i}
              style={[
