  1→import {
  2→  Card,
  3→  GameState,
  4→  GamePhase,
  5→  PlayerState,
  6→  BasraType,
  7→  CaptureResult,
  8→  RoundScoreResult,
  9→  createDeck,
 10→  shuffleDeck,
 11→  dealCards,
 12→  processPlay,
 13→  calculateRoundScores,
 14→  checkWinner,
 15→  CARDS_PER_DEAL,
 16→  INITIAL_TABLE_CARDS,
 17→} from '@basra/shared';
 18→
 19→let playerIdCounter = 0;
 20→
 21→function createPlayerId(): string {
 22→  return `player_${++playerIdCounter}_${Date.now()}`;
 23→}
 24→
 25→function createPlayerState(id: string, nickname: string): PlayerState {
 26→  return {
 27→    id,
 28→    nickname,
 29→    hand: [],
 30→    capturedCards: [],
 31→    capturedCount: 0,
 32→    basras: 0,
 33→    jackBasras: 0,
 34→    score: 0,
 35→    roundScore: 0,
 36→  };
 37→}
 38→
 39→export class GameEngine {
 40→  private state: GameState;
 41→
 42→  constructor(roomCode: string, targetScore: number) {
 43→    this.state = {
 44→      roomCode,
 45→      phase: 'waiting',
 46→      table: [],
 47→      deck: [],
 48→      deckRemaining: 0,
 49→      currentTurn: '',
 50→      dealer: '',
 51→      players: [null as any, null as any],
 52→      targetScore,
 53→      roundNumber: 0,
 54→      lastCapture: null,
 55→      lastCapturePlayerId: null,
 56→      dealsLeft: 0,
 57→    };
 58→  }
 59→
 60→  addPlayer(nickname: string): string {
 61→    const id = createPlayerId();
 62→    const player = createPlayerState(id, nickname);
 63→
 64→    if (!this.state.players[0]) {
 65→      this.state.players[0] = player;
 66→    } else if (!this.state.players[1]) {
 67→      this.state.players[1] = player;
 68→    } else {
 69→      throw new Error('Room is full');
 70→    }
 71→
 72→    return id;
 73→  }
 74→
 75→  getPlayerCount(): number {
 76→    return this.state.players.filter(p => p != null).length;
 77→  }
 78→
 79→  getState(): GameState {
 80→    return this.state;
 81→  }
 82→
 83→  getPlayer(playerId: string): PlayerState | undefined {
 84→    return this.state.players.find(p => p?.id === playerId);
 85→  }
 86→
 87→  getOpponent(playerId: string): PlayerState | undefined {
 88→    return this.state.players.find(p => p && p.id !== playerId);
 89→  }
 90→
 91→  startGame(): void {
 92→    if (this.getPlayerCount() < 2) throw new Error('Need 2 players');
 93→
 94→    // First dealer is player 0 (host)
 95→    this.state.dealer = this.state.players[0].id;
 96→    this.state.roundNumber = 1;
 97→    this.startRound();
 98→  }
 99→
100→  private startRound(): void {
101→    // Reset round-specific state
102→    for (const player of this.state.players) {
103→      player.hand = [];
104→      player.capturedCards = [];
105→      player.capturedCount = 0;
106→      player.basras = 0;
107→      player.jackBasras = 0;
108→      player.roundScore = 0;
109→    }
110→
111→    this.state.table = [];
112→    this.state.lastCapture = null;
113→    this.state.lastCapturePlayerId = null;
114→
115→    // Shuffle deck
116→    this.state.deck = shuffleDeck(createDeck());
117→    this.state.deckRemaining = this.state.deck.length;
118→
119→    // Non-dealer plays first
120→    const nonDealer = this.state.players.find(p => p.id !== this.state.dealer)!;
121→    this.state.currentTurn = nonDealer.id;
122→
123→    // First deal: 4 to each player + 4 on table
124→    this.dealInitial();
125→
126→    this.state.phase = 'playing';
127→  }
128→
129→  private dealInitial(): void {
130→    const nonDealer = this.state.players.find(p => p.id !== this.state.dealer)!;
131→    const dealer = this.state.players.find(p => p.id === this.state.dealer)!;
132→
133→    // Deal 4 to non-dealer
134→    const deal1 = dealCards(this.state.deck, CARDS_PER_DEAL);
135→    nonDealer.hand = deal1.dealt;
136→    this.state.deck = deal1.remaining;
137→
138→    // Deal 4 to dealer
139→    const deal2 = dealCards(this.state.deck, CARDS_PER_DEAL);
140→    dealer.hand = deal2.dealt;
141→    this.state.deck = deal2.remaining;
142→
143→    // Deal 4 to table
144→    const deal3 = dealCards(this.state.deck, INITIAL_TABLE_CARDS);
145→    this.state.table = deal3.dealt;
146→    this.state.deck = deal3.remaining;
147→
148→    this.state.deckRemaining = this.state.deck.length;
149→    // 52 - 4 - 4 - 4 = 40 remaining, 5 more deals of 8 cards = 40
150→    this.state.dealsLeft = 5;
151→  }
152→
153→  dealNextHand(): { hand1: Card[]; hand2: Card[] } | null {
154→    if (this.state.deck.length < CARDS_PER_DEAL * 2) return null;
155→    if (this.state.dealsLeft <= 0) return null;
156→
157→    const nonDealer = this.state.players.find(p => p.id !== this.state.dealer)!;
158→    const dealer = this.state.players.find(p => p.id === this.state.dealer)!;
159→
160→    // Deal 4 to non-dealer
161→    const deal1 = dealCards(this.state.deck, CARDS_PER_DEAL);
162→    nonDealer.hand = deal1.dealt;
163→    this.state.deck = deal1.remaining;
164→
165→    // Deal 4 to dealer
166→    const deal2 = dealCards(this.state.deck, CARDS_PER_DEAL);
167→    dealer.hand = deal2.dealt;
168→    this.state.deck = deal2.remaining;
169→
170→    this.state.deckRemaining = this.state.deck.length;
171→    this.state.dealsLeft--;
172→
173→    // Non-dealer plays first
174→    this.state.currentTurn = nonDealer.id;
175→
176→    return {
177→      hand1: nonDealer.hand,
178→      hand2: dealer.hand,
179→    };
180→  }
181→
182→  playCard(playerId: string, cardId: string): {
183→    card: Card;
184→    captured: Card[];
185→    basraType: BasraType;
186→    tableAfter: Card[];
187→    needsDeal: boolean;
188→    roundOver: boolean;
189→  } {
190→    if (this.state.phase !== 'playing') {
191→      throw new Error('Game is not in playing phase');
192→    }
193→
194→    if (this.state.currentTurn !== playerId) {
195→      throw new Error('Not your turn');
196→    }
197→
198→    const player = this.getPlayer(playerId)!;
199→    const cardIndex = player.hand.findIndex(c => c.id === cardId);
200→    if (cardIndex === -1) {
201→      throw new Error('Card not in your hand');
202→    }
203→
204→    // Remove card from hand
205→    const [card] = player.hand.splice(cardIndex, 1);
206→
207→    // Process capture
208→    const { captured, basraType } = processPlay(card, this.state.table);
209→
210→    if (captured.length > 0) {
211→      // Remove captured cards from table
212→      this.state.table = this.state.table.filter(c => !captured.some(cap => cap.id === c.id));
213→
214→      // Add captured cards + the played card to player's pile
215→      player.capturedCards.push(card, ...captured);
216→      player.capturedCount = player.capturedCards.length;
217→      this.state.lastCapturePlayerId = playerId;
218→
219→      // Track basras
220→      if (basraType === 'basra') {
221→        player.basras++;
222→      } else if (basraType === 'jack-basra') {
223→        player.jackBasras++;
224→      }
225→
226→      this.state.lastCapture = {
227→        playerId,
228→        card,
229→        capturedCards: captured,
230→        isBasra: basraType === 'basra',
231→        isJackBasra: basraType === 'jack-basra',
232→      };
233→    } else {
234→      // Card stays on table
235→      this.state.table.push(card);
236→      this.state.lastCapture = null;
237→    }
238→
239→    const tableAfter = [...this.state.table];
240→
241→    // Switch turns
242→    const opponent = this.getOpponent(playerId)!;
243→    this.state.currentTurn = opponent.id;
244→
245→    // Check if both players' hands are empty
246→    const bothHandsEmpty = this.state.players.every(p => p.hand.length === 0);
247→    let needsDeal = false;
248→    let roundOver = false;
249→
250→    if (bothHandsEmpty) {
251→      if (this.state.dealsLeft > 0) {
252→        needsDeal = true;
253→      } else {
254→        roundOver = true;
255→      }
256→    }
257→
258→    return {
259→      card,
260→      captured,
261→      basraType,
262→      tableAfter,
263→      needsDeal,
264→      roundOver,
265→    };
266→  }
267→
268→  endRound(): {
269→    scores: RoundScoreResult;
270→    gameOver: boolean;
271→    winnerId?: string;
272→  } {
273→    // Remaining table cards go to last player who captured
274→    if (this.state.lastCapturePlayerId && this.state.table.length > 0) {
275→      const lastCapturer = this.getPlayer(this.state.lastCapturePlayerId)!;
276→      lastCapturer.capturedCards.push(...this.state.table);
277→      lastCapturer.capturedCount = lastCapturer.capturedCards.length;
278→      this.state.table = [];
279→    }
280→
281→    // Calculate scores
282→    const scores = calculateRoundScores(this.state.players[0], this.state.players[1]);
283→
284→    this.state.players[0].roundScore = scores.player1RoundPoints;
285→    this.state.players[1].roundScore = scores.player2RoundPoints;
286→    this.state.players[0].score += scores.player1RoundPoints;
287→    this.state.players[1].score += scores.player2RoundPoints;
288→
289→    // Check winner
290→    const winner = checkWinner(this.state.players, this.state.targetScore);
291→
292→    this.state.phase = winner ? 'game-over' : 'round-end';
293→
294→    return {
295→      scores,
296→      gameOver: !!winner,
297→      winnerId: winner?.id,
298→    };
299→  }
300→
301→  startNextRound(): void {
302→    // Swap dealer
303→    this.state.dealer = this.state.players.find(p => p.id !== this.state.dealer)!.id;
304→    this.state.roundNumber++;
305→    this.startRound();
306→  }
307→
308→  resetForRematch(): void {
309→    for (const player of this.state.players) {
310→      player.score = 0;
311→    }
312→    this.state.roundNumber = 0;
313→    this.state.dealer = this.state.players[0].id;
314→    this.state.roundNumber = 1;
315→    this.startRound();
316→  }
317→}
