  1→import { GameState, PlayerState, DEFAULT_TARGET_SCORE } from '@basra/shared';
  2→import { generateRoomCode } from './utils/room-code';
  3→import { GameEngine } from './game-engine';
  4→
  5→export interface Room {
  6→  code: string;
  7→  engine: GameEngine;
  8→  playerSockets: Map<string, string>; // playerId -> socketId
  9→  createdAt: number;
 10→}
 11→
 12→export class RoomManager {
 13→  private rooms = new Map<string, Room>();
 14→  private socketToRoom = new Map<string, string>(); // socketId -> roomCode
 15→  private socketToPlayer = new Map<string, string>(); // socketId -> playerId
 16→
 17→  createRoom(socketId: string, nickname: string, targetScore?: number): Room {
 18→    let code: string;
 19→    do {
 20→      code = generateRoomCode();
 21→    } while (this.rooms.has(code));
 22→
 23→    const engine = new GameEngine(code, targetScore ?? DEFAULT_TARGET_SCORE);
 24→    const playerId = engine.addPlayer(nickname);
 25→
 26→    const room: Room = {
 27→      code,
 28→      engine,
 29→      playerSockets: new Map([[playerId, socketId]]),
 30→      createdAt: Date.now(),
 31→    };
 32→
 33→    this.rooms.set(code, room);
 34→    this.socketToRoom.set(socketId, code);
 35→    this.socketToPlayer.set(socketId, playerId);
 36→
 37→    return room;
 38→  }
 39→
 40→  joinRoom(socketId: string, roomCode: string, nickname: string): { room: Room; playerId: string } | null {
 41→    const room = this.rooms.get(roomCode);
 42→    if (!room) return null;
 43→
 44→    if (room.engine.getPlayerCount() >= 2) return null;
 45→
 46→    const playerId = room.engine.addPlayer(nickname);
 47→    room.playerSockets.set(playerId, socketId);
 48→    this.socketToRoom.set(socketId, roomCode);
 49→    this.socketToPlayer.set(socketId, playerId);
 50→
 51→    return { room, playerId };
 52→  }
 53→
 54→  getRoom(roomCode: string): Room | undefined {
 55→    return this.rooms.get(roomCode);
 56→  }
 57→
 58→  getRoomBySocket(socketId: string): Room | undefined {
 59→    const code = this.socketToRoom.get(socketId);
 60→    if (!code) return undefined;
 61→    return this.rooms.get(code);
 62→  }
 63→
 64→  getPlayerId(socketId: string): string | undefined {
 65→    return this.socketToPlayer.get(socketId);
 66→  }
 67→
 68→  getSocketId(room: Room, playerId: string): string | undefined {
 69→    return room.playerSockets.get(playerId);
 70→  }
 71→
 72→  getOpponentSocketId(room: Room, playerId: string): string | undefined {
 73→    for (const [pid, sid] of room.playerSockets) {
 74→      if (pid !== playerId) return sid;
 75→    }
 76→    return undefined;
 77→  }
 78→
 79→  removeSocket(socketId: string): { room: Room; playerId: string } | null {
 80→    const roomCode = this.socketToRoom.get(socketId);
 81→    const playerId = this.socketToPlayer.get(socketId);
 82→    if (!roomCode || !playerId) return null;
 83→
 84→    const room = this.rooms.get(roomCode);
 85→    if (!room) return null;
 86→
 87→    room.playerSockets.delete(playerId);
 88→    this.socketToRoom.delete(socketId);
 89→    this.socketToPlayer.delete(socketId);
 90→
 91→    // If room is empty, clean it up
 92→    if (room.playerSockets.size === 0) {
 93→      this.rooms.delete(roomCode);
 94→    }
 95→
 96→    return { room, playerId };
 97→  }
 98→
 99→  deleteRoom(roomCode: string): void {
100→    const room = this.rooms.get(roomCode);
101→    if (!room) return;
102→
103→    for (const [, socketId] of room.playerSockets) {
104→      this.socketToRoom.delete(socketId);
105→      this.socketToPlayer.delete(socketId);
106→    }
107→    this.rooms.delete(roomCode);
108→  }
109→
110→  /** Clean up rooms older than maxAge (ms) with no active connections */
111→  cleanupStaleRooms(maxAge: number = 30 * 60 * 1000): void {
112→    const now = Date.now();
113→    for (const [code, room] of this.rooms) {
114→      if (room.playerSockets.size === 0 && now - room.createdAt > maxAge) {
115→        this.rooms.delete(code);
116→      }
117→    }
118→  }
119→}
120→

