 4→export function registerConnectionHandlers(
 5→  io: Server,
 6→  socket: Socket,
 7→  roomManager: RoomManager
 8→): void {
 9→  socket.on('disconnect', () => {
10→    const result = roomManager.removeSocket(socket.id);
11→    if (!result) return;
12→
13→    const { room, playerId } = result;
14→
15→    // Notify opponent about disconnection
16→    for (const [pid, sid] of room.playerSockets) {
17→      if (pid !== playerId) {
18→        io.to(sid).emit('opponent-disconnected', {});
19→      }
20→    }
21→
22→    console.log(`Player ${playerId} disconnected from room ${room.code}`);
23→  });
24→}
