 67→export function registerGameHandlers(
 68→  io: Server,
 69→  socket: Socket,
 70→  roomManager: RoomManager
 71→): void {
 72→  socket.on('play-card', (data: PlayCardPayload) => {
 73→    try {
 74→      const room = roomManager.getRoomBySocket(socket.id);
 75→      const playerId = roomManager.getPlayerId(socket.id);
 76→      if (!room || !playerId) {
 77→        socket.emit('error', { message: 'Not in a room' });
 78→        return;
 79→      }
 80→
 81→      const result = room.engine.playCard(playerId, data.cardId);
 82→      const player = room.engine.getPlayer(playerId)!;
 83→
 84→      const playedPayload: CardPlayedPayload = {
 85→        playerId,
 86→        card: result.card,
 87→        capturedCards: result.captured,
 88→        isBasra: result.basraType === 'basra',
 89→        isJackBasra: result.basraType === 'jack-basra',
 90→        tableAfter: result.tableAfter,
 91→        currentTurn: room.engine.getState().currentTurn,
 92→        playerCapturedCount: player.capturedCount,
 93→      };
 94→
 95→      // Broadcast to all players in room
 96→      for (const [, sid] of room.playerSockets) {
 97→        io.to(sid).emit('card-played', playedPayload);
 98→      }
 99→
100→      if (result.roundOver) {
101→        // Short delay before showing round results
102→        setTimeout(() => emitRoundEnd(io, room), 500);
103→      } else if (result.needsDeal) {
104→        // Deal next hand
105→        setTimeout(() => {
106→          const dealt = room.engine.dealNextHand();
107→          if (dealt) {
108→            emitDeal(io, room);
109→          }
110→        }, 500);
111→      } else {
112→        // Notify next player it's their turn
113→        const nextTurn = room.engine.getState().currentTurn;
114→        const nextSid = room.playerSockets.get(nextTurn);
115→        if (nextSid) {
116→          io.to(nextSid).emit('your-turn', {});
117→        }
118→      }
119→    } catch (err: any) {
120→      socket.emit('error', { message: err.message });
121→    }
122→  });
123→
124→  socket.on('next-round', () => {
125→    try {
126→      const room = roomManager.getRoomBySocket(socket.id);
127→      if (!room) {
128→        socket.emit('error', { message: 'Not in a room' });
129→        return;
130→      }
131→
132→      room.engine.startNextRound();
133→      const state = room.engine.getState();
134→
135→      for (const player of state.players) {
136→        const sid = room.playerSockets.get(player.id);
137→        if (!sid) continue;
138→
139→        const opponent = state.players.find(p => p.id !== player.id)!;
140→
141→        io.to(sid).emit('game-start', {
142→          hand: player.hand,
143→          tableCards: state.table,
144→          deckRemaining: state.deckRemaining,
145→          currentTurn: state.currentTurn,
146→          dealer: state.dealer,
147→          opponentCardCount: opponent.hand.length,
148→          roundNumber: state.roundNumber,
149→          targetScore: state.targetScore,
150→          players: state.players.map(p => ({
151→            id: p.id,
152→            nickname: p.nickname,
153→            score: p.score,
154→          })),
155→        });
156→
157→        if (state.currentTurn === player.id) {
158→          io.to(sid).emit('your-turn', {});
159→        }
160→      }
161→    } catch (err: any) {
162→      socket.emit('error', { message: err.message });
163→    }
164→  });
165→
166→  socket.on('rematch', () => {
167→    try {
168→      const room = roomManager.getRoomBySocket(socket.id);
169→      if (!room) {
170→        socket.emit('error', { message: 'Not in a room' });
171→        return;
172→      }
173→
174→      room.engine.resetForRematch();
175→      const state = room.engine.getState();
176→
177→      for (const player of state.players) {
178→        const sid = room.playerSockets.get(player.id);
179→        if (!sid) continue;
180→
181→        const opponent = state.players.find(p => p.id !== player.id)!;
182→
183→        io.to(sid).emit('game-start', {
184→          hand: player.hand,
185→          tableCards: state.table,
186→          deckRemaining: state.deckRemaining,
187→          currentTurn: state.currentTurn,
188→          dealer: state.dealer,
189→          opponentCardCount: opponent.hand.length,
190→          roundNumber: state.roundNumber,
191→          targetScore: state.targetScore,
192→          players: state.players.map(p => ({
193→            id: p.id,
194→            nickname: p.nickname,
195→            score: p.score,
196→          })),
197→        });
198→
199→        if (state.currentTurn === player.id) {
200→          io.to(sid).emit('your-turn', {});
201→        }
202→      }
203→    } catch (err: any) {
204→      socket.emit('error', { message: err.message });
205→    }
206→  });
207→}
